int tlExpressionAnimChunk16::sortPriority = -1;

tlExpressionAnimChunk16::tlExpressionAnimChunk16()
{
    Init();
}

tlExpressionAnimChunk16::tlExpressionAnimChunk16(const tlExpressionAnimChunk16& ch)
{
    Init();
    *this = ch;
}

tlExpressionAnimChunk16::~tlExpressionAnimChunk16()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlExpressionAnimChunk16::tlExpressionAnimChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_EXPRESSION_ANIM);
    ident = P3D_EXPRESSION_ANIM;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    numframes = f->GetLong();
    framerate = f->GetFloat();
    cyclic = f->GetLong();
    numchannel = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_EXPRESSION_ANIM);
    }
}

void
tlExpressionAnimChunk16::Init()
{
    ident = P3D_EXPRESSION_ANIM;
    name = NULL;
    version = 0;
    numframes = 0;
    framerate = 0.0f;
    cyclic = 0;
    numchannel = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_EXPRESSION_ANIM);
    }
}

long 
tlExpressionAnimChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += sizeof( numframes );
    s += sizeof( framerate );
    s += sizeof( cyclic );
    s += sizeof( numchannel );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlExpressionAnimChunk16&
tlExpressionAnimChunk16::operator=(const tlExpressionAnimChunk16& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    version = a.version;
    numframes = a.numframes;
    framerate = a.framerate;
    cyclic = a.cyclic;
    numchannel = a.numchannel;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlExpressionAnimChunk16::operator==(const tlDataChunk& a)
{

    const tlExpressionAnimChunk16* aptr = dynamic_cast<const tlExpressionAnimChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(numframes == aptr->numframes))
    {
        return false;
    }
    if(!(framerate == aptr->framerate))
    {
        return false;
    }
    if(!(cyclic == aptr->cyclic))
    {
        return false;
    }
    if(!(numchannel == aptr->numchannel))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlExpressionAnimChunk16::NameCompare(const tlDataChunk& a)
{

    const tlExpressionAnimChunk16* aptr = dynamic_cast<const tlExpressionAnimChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


