void
tlExpressionAnimChunk16::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutLong(version);
        f->PutLong(numframes);
        f->PutFloat(framerate);
        f->PutLong(cyclic);
        f->PutLong(numchannel);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlExpressionAnimChunk16::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlExpressionAnimChunk16 (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name       = \"%s\"\n",indent,"",name);
    printf("%*s  Version    = %ld\n",indent,"",version);
    printf("%*s  NumFrames  = %ld\n",indent,"",numframes);
    printf("%*s  FrameRate  = %f\n",indent,"",framerate);
    printf("%*s  Cyclic     = %ld\n",indent,"",cyclic);
    printf("%*s  NumChannel = %ld\n",indent,"",numchannel);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlExpressionAnimChunk16::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name      \n",indent,"",name);
    printf("%*s  int   %12ld # Version   \n",indent,"",version);
    printf("%*s  int   %12ld # NumFrames \n",indent,"",numframes);
    printf("%*s  float %12f # FrameRate \n",indent,"",framerate);
    printf("%*s  int   %12ld # Cyclic    \n",indent,"",cyclic);
    printf("%*s  int   %12ld # NumChannel\n",indent,"",numchannel);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

