bool 
tlExpressionMixerChunk16::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
            strdelete(name);
            name = strnew(new_val);
            return true;
        case 1:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                version = tmp;
                return true;
            }
            return false;
        }
        case 2:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                type = tmp;
                return true;
            }
            return false;
        }
        case 3:
            strdelete(targetname);
            targetname = strnew(new_val);
            return true;
        case 4:
            strdelete(expressiongroupname);
            expressiongroupname = strnew(new_val);
            return true;
        default:
            return false;
    }
}

